window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-school-bus"] = window.COURSE_LANG["cdl-school-bus"] || {};
window.COURSE_LANG["cdl-school-bus"]["es"] = [
  {"id":1,"q":"La zona de peligro alrededor de un autobus escolar se describe mejor como:","opts":["Solo el area detras del autobus","Solo el lado del conductor","El area en todos los lados donde los estudiantes corren mas riesgo de ser atropellados","Solo el espacio debajo del motor"],"re":"La zona de peligro es el area en todos los lados del autobus donde los estudiantes corren riesgo de ser atropellados."},
  {"id":2,"q":"La zona de peligro se extiende desde el autobus aproximadamente:","opts":["1 pie a cada lado","Hasta 10 pies alrededor del autobus, y mas lejos al frente","Solo 50 pies por detras","Un cuarto de milla"],"re":"Las zonas de peligro llegan hasta unos 10 pies alrededor del autobus y aun mas al frente."},
  {"id":3,"q":"La zona de peligro mas riesgosa para los estudiantes es:","opts":["Muy por encima del techo","Muy por detras del autobus","Dentro del compartimento de equipaje","Directamente al frente del autobus"],"re":"El area directamente al frente del autobus es la mas peligrosa, donde es mas dificil ver a los estudiantes."},
  {"id":4,"q":"Los espejos de cruce (crossover) van en las esquinas delanteras del autobus para:","opts":["Permitir ver la zona de peligro delantera y el area junto al autobus","Mostrar la temperatura del motor","Reemplazar el espejo retrovisor","Vigilar el trafico dos carriles mas alla"],"re":"Los espejos de cruce muestran la zona de peligro delantera y el area justo al frente y a los lados del autobus."},
  {"id":5,"q":"Los espejos convexos exteriores sirven principalmente para ver:","opts":["El tablero de instrumentos","Recto por la carretera al frente","Una vista mas amplia de los lados del autobus","Dentro del compartimento del motor"],"re":"Los espejos convexos dan una vista amplia de los lados del autobus, aunque los objetos se ven mas pequenos y lejanos."},
  {"id":6,"q":"Los espejos planos exteriores (West Coast) sirven para vigilar:","opts":["El techo del autobus","Los lados y el area detras del autobus","Solo la defensa delantera","El medidor de combustible"],"re":"Los espejos planos muestran a lo largo de los lados del autobus y el trafico y los estudiantes detras."},
  {"id":7,"q":"Cuando debe el conductor ajustar todos los espejos?","opts":["Solo despues de un accidente","Una vez al mes","Nunca, lo hace el taller","Antes del viaje, para tener la vista completa"],"re":"Ajusta y revisa todos los espejos antes del viaje para tener la vista correcta de las zonas de peligro."},
  {"id":8,"q":"Como los espejos no muestran todo, el conductor debe recordar que:","opts":["Aun existen puntos ciegos y los estudiantes pueden desaparecer de la vista","Los espejos eliminan todos los puntos ciegos","No hace falta mirar si los espejos estan limpios","Los espejos convexos muestran la distancia exacta"],"re":"Aun con espejos hay puntos ciegos; nunca supongas que el area esta despejada sin revisar."},
  {"id":9,"q":"Al acercarte a una parada para recoger estudiantes, primero activas:","opts":["Las luces rojas intermitentes","Las luces interiores del techo","Las luces ambar (amarillas) de advertencia","Solo las intermitentes de emergencia"],"re":"Activa primero las luces ambar de advertencia, unos 100 a 300 pies antes de la parada."},
  {"id":10,"q":"A que distancia antes de la parada debes encender las luces ambar?","opts":["10 a 20 pies","100 a 300 pies","Media milla","Justo en la parada"],"re":"Activa las luces ambar entre unos 100 y 300 pies antes de la parada, o segun lo exija tu estado."},
  {"id":11,"q":"Despues de detener por completo el autobus para cargar estudiantes, activas:","opts":["Solo los faros","Las luces ambar otra vez","No hace falta nada mas","Las luces rojas intermitentes y el brazo de alto"],"re":"Ya detenido, enciende las luces rojas intermitentes y extiende el brazo de alto antes de que se acerquen los estudiantes."},
  {"id":12,"q":"Antes de subir, los estudiantes que esperan en la parada deben:","opts":["Esperar en un lugar seguro, lejos del camino, hasta que el autobus se detenga","Pararse en el carril de trafico","Caminar por detras del autobus","Perseguir el autobus mientras frena"],"re":"Los estudiantes deben esperar en un lugar seguro lejos del trafico hasta que el autobus se detenga y abra la puerta."},
  {"id":13,"q":"Los estudiantes que deben cruzar la calle para subir deben cruzar:","opts":["Por detras del autobus, fuera de la vista","A unos 10 pies al frente del autobus, a la vista del conductor","Entre las ruedas traseras","Por donde sea mas rapido"],"re":"Quienes cruzan caminan a unos 10 pies al frente del autobus para que el conductor los vea con claridad."},
  {"id":14,"q":"Los estudiantes que deben cruzar deben pisar la calle solo:","opts":["En cuanto llegan a la acera","Cuando otro auto les hace senas","Cuando el conductor indica que es seguro","Cuando se encienden las luces ambar"],"re":"Quienes cruzan esperan a que el conductor indique que el trafico se detuvo y es seguro."},
  {"id":15,"q":"Despues de que los estudiantes suben, el conductor debe:","opts":["Arrancar de inmediato","Tocar el claxon dos veces","Saltarse el conteo para ahorrar tiempo","Contarlos y asegurarse de que esten sentados antes de avanzar"],"re":"Cuenta a los estudiantes y confirma que todos esten a bordo y sentados antes de arrancar."},
  {"id":16,"q":"Antes de que el autobus avance tras cargar, el conductor tambien debe revisar:","opts":["Los espejos y las zonas de peligro por algun estudiante tardio o que cruza","Solo la radio","Los frenos del remolque","Nada si la puerta esta cerrada"],"re":"Revisa de nuevo todos los espejos y las zonas de peligro por algun estudiante tardio, que cruza o cercano al autobus."},
  {"id":17,"q":"Mientras las luces rojas parpadean y el brazo de alto esta afuera, el trafico que viene debe normalmente:","opts":["Pasar el autobus despacio","Detenerse, salvo que una barrera de autopista dividida los separe","Acelerar para despejar el area","Usar el acotamiento"],"re":"Los conductores en ambos sentidos deben detenerse por las luces rojas y el brazo de alto, salvo donde una barrera divide la via."},
  {"id":18,"q":"Donde ocurren la mayoria de las muertes de estudiantes relacionadas con el autobus escolar?","opts":["En la autopista a alta velocidad","Dentro del autobus durante el trayecto","En la zona de peligro al cargar y descargar","En el garaje del autobus"],"re":"La mayoria de las muertes con autobuses escolares ocurren en la zona de peligro al cargar o descargar estudiantes."},
  {"id":19,"q":"Al descargar, antes de que los estudiantes bajen debes:","opts":["Activar las luces rojas intermitentes y el brazo de alto","Abrir la tapa del motor","Apagar los faros","Tocar el claxon para avisar a la calle"],"re":"Igual que al cargar, activa las luces rojas y el brazo de alto antes de que los estudiantes bajen del autobus."},
  {"id":20,"q":"Cuando los estudiantes bajan, debes indicarles que:","opts":["Corran rapido a casa","Esperen debajo del autobus","Se paren junto a las llantas traseras","Se alejen al menos 10 pies del autobus, fuera de la zona de peligro"],"re":"Indica a los estudiantes que se alejen bien del autobus, al menos 10 pies, para que puedas verlos y esten despejados."},
  {"id":21,"q":"Un estudiante que debe cruzar la calle al bajar debe:","opts":["Cruzar rapido por detras del autobus","Caminar unos 10 pies al frente y cruzar a tu senal","Cruzar entre autos estacionados","Esperar a que el autobus se vaya primero"],"re":"Quienes cruzan caminan a unos 10 pies al frente, a tu vista, y cruzan solo cuando indicas que es seguro."},
  {"id":22,"q":"Despues de descargar, antes de mover el autobus debes:","opts":["Suponer que todos estan despejados","Avanzar de inmediato para no atrasarte","Contar a los estudiantes y ubicar a todos, luego revisar espejos y zonas de peligro","Solo revisar la puerta"],"re":"Cuenta a los estudiantes que bajaron, ubica a todos y revisa los espejos y las zonas de peligro antes de avanzar."},
  {"id":23,"q":"Si cuentas a los estudiantes que bajan y falta uno, debes:","opts":["Asegurar el autobus y revisar alrededor y debajo antes de avanzar","Irte y reportarlo despues","Suponer que el nino se fue caminando","Tocar el claxon y esperar diez segundos"],"re":"Si falta un estudiante, pon el freno, asegura el autobus y revisa alrededor y debajo antes de avanzar."},
  {"id":24,"q":"Un peligro comun al descargar es un estudiante que:","opts":["Se queda sentado tranquilo","Camina derecho a casa","Ayuda al conductor","Regresa al autobus por algo que se le cayo u olvido"],"re":"Cuidado con el nino que vuelve corriendo hacia el autobus para recoger algo caido u olvidado."},
  {"id":25,"q":"Nunca debes suponer que:","opts":["El brazo de alto funciona","Un nino cerca del autobus ya esta despejado","Los espejos estan ajustados","La puerta esta cerrada"],"re":"Nunca supongas que un nino ya esta despejado del autobus; verifica con los espejos y una revision directa antes de avanzar."},
  {"id":26,"q":"En un cruce de ferrocarril, el autobus escolar debe detenerse a que distancia del riel mas cercano?","opts":["A 5 pies","A 100 a 200 pies","Entre 15 y 50 pies","Justo sobre las vias"],"re":"Deten el autobus entre 15 y 50 pies antes del riel mas cercano en el cruce de ferrocarril."},
  {"id":27,"q":"Antes de cruzar las vias, el conductor debe apagar:","opts":["Los ventiladores ruidosos y la radio para poder escuchar un tren","Los faros","Las luces de freno","El motor"],"re":"Silencia los ventiladores, el soplador de la calefaccion y la radio para escuchar un tren que se acerque."},
  {"id":28,"q":"En el cruce el conductor tambien debe:","opts":["Mantener todas las ventanas cerradas","Abrir la puerta de servicio y una ventana para mirar y escuchar","Cubrir los espejos","Tocar el claxon sin parar"],"re":"Abre la puerta y una ventana del conductor, luego mira a ambos lados y escucha si viene un tren antes de cruzar."},
  {"id":29,"q":"Mientras el autobus cruza las vias, el conductor debe:","opts":["Detenerse sobre los rieles para mirar otra vez","Bajar de marcha a mitad del cruce","Indicar a los estudiantes que se asomen","No cambiar de marcha, para no quedarse parado sobre las vias"],"re":"Nunca cambies de marcha al cruzar; una mala metida de marcha podria dejar el autobus parado sobre las vias."},
  {"id":30,"q":"Un autobus escolar debe detenerse en:","opts":["Solo cruces con barreras","Solo cruces con luces","Cada cruce, salvo que este marcado oficialmente como exento","Ningun cruce si hay poco trafico"],"re":"Deten en cada cruce de ferrocarril, salvo que un letrero oficial de exento o un oficial indique lo contrario."},
  {"id":31,"q":"Cuando te detienes en un cruce, debes parar:","opts":["Lo bastante atras para quedar despejado si el autobus rueda un poco","Con la defensa delantera sobre el primer riel","En medio de las vias","Solo si hay un tren a la vista"],"re":"Deten lo bastante atras para quedar lejos de los rieles aunque el autobus se deslice un poco al frente."},
  {"id":32,"q":"Antes de avanzar por las vias, debes asegurarte de que:","opts":["La radio este encendida","Los estudiantes esten de pie","La barrera este rota","Hay espacio suficiente para librar por completo las vias del otro lado"],"re":"Asegurate de que haya espacio del otro lado para que el autobus libre por completo las vias sin detenerse."},
  {"id":33,"q":"Si el autobus se apaga o queda atrapado en las vias con un tren acercandose, el conductor debe:","opts":["Quedarse sentado e intentar arrancar","Bajar a todos y alejarlos de las vias, hacia el tren en angulo","Esconderse bajo los asientos","Esperar a que pase el tren"],"re":"Evacua de inmediato y aleja a todos bien de las vias, caminando hacia el tren en angulo."},
  {"id":34,"q":"Evacuar el autobus es obligatorio cuando:","opts":["Falla la radio","Un estudiante habla fuerte","Hay un incendio o riesgo de incendio","El autobus va unos minutos tarde"],"re":"Debes evacuar si hay un incendio o riesgo de incendio."},
  {"id":35,"q":"Tambien se requiere evacuar si el autobus esta detenido:","opts":["Sobre o cerca de vias de ferrocarril","En una parada normal","En el estacionamiento de la escuela","En un semaforo en rojo"],"re":"Evacua si el autobus queda parado sobre o cerca de las vias, donde un tren podria golpearlo."},
  {"id":36,"q":"Otra situacion que exige evacuar es:","opts":["Una llanta de refaccion ponchada","Una calefaccion ruidosa","Un cortador de cinturon faltante","Una amenaza de materiales peligrosos o el riesgo de una colision"],"re":"Evacua cuando hay un derrame de materiales peligrosos o el autobus corre riesgo de colision."},
  {"id":37,"q":"Si hay tiempo y es seguro, quien decide si evacuar o mantener a los estudiantes en el autobus?","opts":["El estudiante mayor","El conductor, segun lo que sea mas seguro","Un automovilista que pasa","Nadie, es automatico"],"re":"El conductor debe juzgar si es mas seguro quedarse en el autobus o evacuar."},
  {"id":38,"q":"En general, es mas seguro mantener a los estudiantes en el autobus cuando:","opts":["Hay un incendio a bordo","El autobus esta sobre las vias","Evacuar los pondria en mayor peligro, como en una autopista transitada","Hay una fuga de combustible"],"re":"Si bajar del autobus expone a los estudiantes a mas peligro, suele ser mas seguro mantenerlos a bordo."},
  {"id":39,"q":"Cuando debes evacuar, una buena practica es:","opts":["Asignar a los estudiantes mayores que ayuden a los menores y guiarlos a un lugar seguro","Dejar que todos se lancen a la puerta a la vez","Mantener la puerta cerrada hasta que llegue ayuda","Sacar a los estudiantes solo de a una ventana"],"re":"Usa a estudiantes mayores como ayudantes y guia a todos a un lugar seguro lejos del autobus."},
  {"id":40,"q":"Despues de evacuar, los estudiantes deben ser llevados a un lugar que este:","opts":["Justo al lado del autobus","En el acotamiento de la via","Entre los carriles","A una distancia segura del autobus y el trafico, al menos 100 pies"],"re":"Lleva a los estudiantes al menos 100 pies fuera de la via, lejos del autobus, el trafico y cualquier peligro."},
  {"id":41,"q":"Antes de conducir cada dia, debes saber:","opts":["Solo donde esta la tapa del combustible","Como operar cada salida de emergencia del autobus","Los nombres de todos los padres","La velocidad maxima del autobus"],"re":"Conoce la ubicacion y el manejo de cada salida de emergencia antes de empezar a conducir."},
  {"id":42,"q":"Practicar simulacros de evacuacion con los estudiantes ayuda porque:","opts":["Solo se exige en autobuses nuevos","Reemplaza la necesidad de salidas","Los estudiantes aprenden que hacer con calma en una emergencia real","Permite al conductor saltarse las inspecciones"],"re":"Los simulacros regulares ensenan a los estudiantes a salir rapido y con calma en una emergencia real."},
  {"id":43,"q":"Dar reversa con un autobus escolar es:","opts":["Peligroso y se debe evitar siempre que sea posible","Recomendado para ahorrar tiempo","Seguro gracias a los espejos","Obligatorio en cada parada"],"re":"Dar reversa es peligroso por los grandes puntos ciegos; evitalo siempre que puedas."},
  {"id":44,"q":"Si es absolutamente necesario dar reversa, debes:","opts":["Retroceder rapido para terminar pronto","Confiar solo en los espejos","Hacer que los estudiantes se paren detras","Usar un guia que te dirija, o bajar y revisar primero"],"re":"Cuando la reversa es inevitable, pon un guia confiable o baja y revisa detras del autobus primero."},
  {"id":45,"q":"Para no golpear un paso a desnivel o cables bajos, el conductor debe vigilar:","opts":["El nivel de combustible","La altura y el espacio libre del autobus","El volumen de la radio","Solo la presion de las llantas"],"re":"Conoce la altura de tu autobus y vigila el espacio libre arriba en puentes, letreros y cables."},
  {"id":46,"q":"Mantener el control de los estudiantes al conducir es importante porque:","opts":["Hace el viaje mas rapido","Es solo cuestion de comodidad","El mal comportamiento puede distraer al conductor y causar un choque","Ahorra combustible"],"re":"La conducta disruptiva puede distraer al conductor; un buen manejo de los estudiantes mantiene a todos mas seguros."},
  {"id":47,"q":"Los procedimientos de carga y descarga deben usarse:","opts":["Solo el primer dia","Solo cuando un adulto observa","Solo con mal clima","Siempre, en cada parada"],"re":"Sigue toda la rutina de carga y descarga siempre para que se vuelva automatica y segura."},
  {"id":48,"q":"Al acercarse a una parada, el autobus debe frenar:","opts":["De forma gradual y suave, atento a estudiantes y trafico","Con frenado fuerte de ultimo segundo","Solo despues de pasar la parada","Sin usar los frenos"],"re":"Frena de forma gradual y observa a los estudiantes y al demas trafico al acercarte a la parada."},
  {"id":49,"q":"Las paradas del autobus escolar deben hacerse:","opts":["Donde el conductor prefiera cada dia","En las paradas designadas de la ruta","Solo en esquinas con semaforo","Tan lejos de la ruta como haga falta"],"re":"Haz las paradas solo en los lugares designados de tu ruta asignada."},
  {"id":50,"q":"Una inspeccion previa al viaje en un autobus escolar siempre debe incluir revisar:","opts":["Solo la lista de estudiantes","El color de los asientos","Las salidas de emergencia, los espejos, las luces de advertencia y el brazo de alto","Solo el aceite del motor"],"re":"En la inspeccion previa, confirma que funcionen las salidas de emergencia, los espejos, las luces de advertencia y el brazo de alto."}
];
